const t=JSON.parse('{"key":"v-70f461f1","path":"/zh/posts/mysql/%E5%9F%BA%E7%A1%80%E7%9F%A5%E8%AF%869%E3%80%81mysql%E4%BA%8B%E5%8A%A1.html","title":"基础知识9、mysql事务","lang":"zh-CN","frontmatter":{"icon":"pen-to-square","date":"2023-07-15T00:00:00.000Z","category":["mysql"],"tag":["mysql事务"],"description":"基础知识9、mysql事务 MySQL中事务的特性 在关系型数据库管理系统中，一个逻辑工作单元要成为事务，必须满足这 4 个特性，即所谓的 ACID：原子性（Atomicity）、一致性（Consistency）、隔离性（Isolation）和持久性（Durability）。 1）原子性 原子性：事务作为一个整体被执行，包含在其中的对数据库的操作要么全部被执行，要么都不执行。 InnoDB存储引擎提供了两种事务日志：redo log(重做日志)和undo log(回滚日志)。其中redo log用于保证事务持久性；undo log则是事务原子性和隔离性实现的基础。","head":[["link",{"rel":"alternate","hreflang":"en-us","href":"https://y-aong.github.io/orderlines_blog/orderlines_blog/posts/mysql/%E5%9F%BA%E7%A1%80%E7%9F%A5%E8%AF%869%E3%80%81mysql%E4%BA%8B%E5%8A%A1.html"}],["meta",{"property":"og:url","content":"https://y-aong.github.io/orderlines_blog/orderlines_blog/zh/posts/mysql/%E5%9F%BA%E7%A1%80%E7%9F%A5%E8%AF%869%E3%80%81mysql%E4%BA%8B%E5%8A%A1.html"}],["meta",{"property":"og:site_name","content":"ORDERLINES"}],["meta",{"property":"og:title","content":"基础知识9、mysql事务"}],["meta",{"property":"og:description","content":"基础知识9、mysql事务 MySQL中事务的特性 在关系型数据库管理系统中，一个逻辑工作单元要成为事务，必须满足这 4 个特性，即所谓的 ACID：原子性（Atomicity）、一致性（Consistency）、隔离性（Isolation）和持久性（Durability）。 1）原子性 原子性：事务作为一个整体被执行，包含在其中的对数据库的操作要么全部被执行，要么都不执行。 InnoDB存储引擎提供了两种事务日志：redo log(重做日志)和undo log(回滚日志)。其中redo log用于保证事务持久性；undo log则是事务原子性和隔离性实现的基础。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:locale:alternate","content":"en-US"}],["meta",{"property":"og:updated_time","content":"2023-07-15T14:57:54.000Z"}],["meta",{"property":"article:author","content":"Y-aong"}],["meta",{"property":"article:tag","content":"mysql事务"}],["meta",{"property":"article:published_time","content":"2023-07-15T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2023-07-15T14:57:54.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"基础知识9、mysql事务\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2023-07-15T00:00:00.000Z\\",\\"dateModified\\":\\"2023-07-15T14:57:54.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Y-aong\\",\\"url\\":\\"https://github.com/Y-aong\\"}]}"]]},"headers":[{"level":2,"title":"MySQL中事务的特性","slug":"mysql中事务的特性","link":"#mysql中事务的特性","children":[]}],"git":{"createdTime":1689433074000,"updatedTime":1689433074000,"contributors":[{"name":"Y-aong","email":"1627469727@qq.com","commits":1}]},"readingTime":{"minutes":3.81,"words":1144},"filePathRelative":"zh/posts/mysql/基础知识9、mysql事务.md","localizedDate":"2023年7月15日","excerpt":"<h1> 基础知识9、mysql事务</h1>\\n<h2> MySQL中事务的特性</h2>\\n<p>在关系型数据库管理系统中，一个逻辑工作单元要成为事务，必须满足这 4 个特性，即所谓的 ACID：原子性（Atomicity）、一致性（Consistency）、隔离性（Isolation）和持久性（Durability）。</p>\\n<p>1）原子性</p>\\n<p>原子性：事务作为一个整体被执行，包含在其中的对数据库的操作要么全部被执行，要么都不执行。</p>\\n<p>InnoDB存储引擎提供了两种事务日志：redo log(重做日志)和undo log(回滚日志)。其中redo log用于保证事务持久性；undo log则是事务原子性和隔离性实现的基础。</p>","autoDesc":true}');export{t as data};
